import fs from "node:fs/promises";
import path from "node:path";

function header(sourceFilePath) {
    return `/*
 * -----------------------------------------------------------------------------
 * ⚠️  AUTO-GENERATED FILE
 * -----------------------------------------------------------------------------
 * This file was generated from:
 *   ${sourceFilePath.replaceAll("\\", "/")}
 * Do NOT edit this file directly.
 * Instead, edit the source file above and run:
 *   pnpm generate-shared
 * -----------------------------------------------------------------------------
 */

`;
}

const NO_HEADER_FILES = new Set(["LICENSE"]);

export async function copyGeneratedFile(file, context) {
    const sourceFilePath = path.relative(process.cwd(), file.source);
    const destination = path.join(context.path, file.name);
    let content = await fs.readFile(file.source, "utf8");
    if (!NO_HEADER_FILES.has(file.name))
        content = header(sourceFilePath) + content;
    await fs.writeFile(destination, content, "utf8");
}
